export interface Property {
  id: string;
  name: string;
  address: string;
  type: 'Casa' | 'Apartamento' | 'Local';
  status: 'Ocupada' | 'Disponible' | 'Mantenimiento';
}

export interface Transaction {
  id: string;
  date: string;
  propertyId: string;
  description: string;
  amount: number;
  category: 'Alquiler' | 'Mantenimiento' | 'Servicios' | 'Impuestos' | 'Otro';
  type: 'Ingreso' | 'Gasto';
}

export interface MaintenanceTask {
  id: string;
  propertyId: string;
  title: string;
  description: string;
  priority: 'Baja' | 'Media' | 'Alta';
  status: 'Pendiente' | 'En Progreso' | 'Completado';
  dueDate: string;
}

export interface Invoice {
  id: string;
  propertyId: string;
  tenantName: string;
  date: string;
  amount: number;
  status: 'Pagada' | 'Pendiente' | 'Vencida';
  items: Array<{ description: string; price: number }>;
}

