import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMaintenanceAdvice(taskTitle: string, description: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Como experto administrador de propiedades, brinda consejos rápidos (máximo 100 palabras) para esta tarea de mantenimiento: ${taskTitle}. Descripción: ${description}. Enfócate en eficiencia de costos y seguridad.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "No se pudo obtener consejo automático en este momento.";
  }
}

export async function analyzeAccounting(data: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analiza los siguientes datos contables de una administración de casas y detecta anomalías o sugiere mejoras financieras. Datos: ${data}. Responde de forma concisa y profesional.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error al analizar contabilidad.";
  }
}

