import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Property, Transaction, MaintenanceTask } from '../types';

interface DashboardProps {
  properties: Property[];
  transactions: Transaction[];
  tasks: MaintenanceTask[];
}

const Dashboard: React.FC<DashboardProps> = ({ properties, transactions, tasks }) => {
  const totalIncome = transactions.filter(t => t.type === 'Ingreso').reduce((acc, curr) => acc + curr.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'Gasto').reduce((acc, curr) => acc + curr.amount, 0);
  const balance = totalIncome - totalExpense;

  const chartData = [
    { name: 'Ingresos', value: totalIncome, fill: '#10b981' },
    { name: 'Gastos', value: totalExpense, fill: '#ef4444' }
  ];

  const maintenanceStats = [
    { name: 'Pendientes', value: tasks.filter(t => t.status === 'Pendiente').length },
    { name: 'En Progreso', value: tasks.filter(t => t.status === 'En Progreso').length },
    { name: 'Completadas', value: tasks.filter(t => t.status === 'Completado').length },
  ];

  return (
    <div className="space-y-8 animate-fadeIn">
      <header>
        <h2 className="text-3xl font-bold text-slate-800">Panel de Control</h2>
        <p className="text-slate-500">Resumen general de tu administración de propiedades.</p>
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <p className="text-slate-500 text-sm font-medium">Balance Total</p>
          <p className={`text-2xl font-bold mt-1 ${balance >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
            ${balance.toLocaleString()}
          </p>
          <div className="mt-4 flex items-center text-xs text-slate-400">
            <span className="bg-emerald-100 text-emerald-600 px-2 py-1 rounded-full">+12% vs mes anterior</span>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <p className="text-slate-500 text-sm font-medium">Propiedades Activas</p>
          <p className="text-2xl font-bold mt-1 text-slate-800">{properties.length}</p>
          <p className="mt-4 text-xs text-slate-400">{properties.filter(p => p.status === 'Ocupada').length} unidades rentadas</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <p className="text-slate-500 text-sm font-medium">Gastos de Mantenimiento</p>
          <p className="text-2xl font-bold mt-1 text-rose-500">${totalExpense.toLocaleString()}</p>
          <p className="mt-4 text-xs text-slate-400">Basado en 15 reparaciones</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <p className="text-slate-500 text-sm font-medium">Tareas Pendientes</p>
          <p className="text-2xl font-bold mt-1 text-amber-500">{tasks.filter(t => t.status !== 'Completado').length}</p>
          <p className="mt-4 text-xs text-slate-400">{tasks.filter(t => t.priority === 'Alta').length} prioridad alta</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Charts Section */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-h-[400px]">
          <h3 className="text-lg font-bold mb-6 text-slate-800">Flujo de Caja</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} 
                />
                <Bar dataKey="value" radius={[8, 8, 0, 0]} barSize={60} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Recent Activity */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold mb-6 text-slate-800">Próximos Mantenimientos</h3>
          <div className="space-y-4">
            {tasks.slice(0, 5).map(task => (
              <div key={task.id} className="flex items-start gap-4 p-3 rounded-xl hover:bg-slate-50 transition-colors">
                <div className={`w-2 h-10 rounded-full flex-shrink-0 ${
                  task.priority === 'Alta' ? 'bg-rose-500' : task.priority === 'Media' ? 'bg-amber-500' : 'bg-slate-300'
