export default Dashboard;

import React, { useState } from 'react';
import { Transaction, Property } from '../types';
import { analyzeAccounting } from '../services/geminiService';

interface AccountingProps {
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  properties: Property[];
}

const Accounting: React.FC<AccountingProps> = ({ transactions, setTransactions, properties }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<string | null>(null);

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    const dataString = JSON.stringify(transactions.map(t => ({ d: t.description, a: t.amount, ty: t.type })));
    const result = await analyzeAccounting(dataString);
    setAnalysis(result || "Análisis no disponible.");
    setIsAnalyzing(false);
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Contabilidad</h2>
          <p className="text-slate-500">Gestión de ingresos, gastos y auditoría.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing}
            className="px-4 py-2 bg-indigo-100 text-indigo-700 rounded-xl font-semibold flex items-center gap-2 hover:bg-indigo-200 transition-colors disabled:opacity-50"
          >
            {isAnalyzing ? 'Analizando...' : 'Análisis Inteligente (IA)'}
          </button>
          <button className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-md hover:bg-indigo-700 transition-all">
            + Nuevo Movimiento
          </button>
        </div>
      </div>

      {analysis && (
        <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-2xl relative">
          <button onClick={() => setAnalysis(null)} className="absolute top-4 right-4 text-indigo-400 hover:text-indigo-600">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
          <h3 className="text-indigo-900 font-bold mb-2 flex items-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
            Recomendación de la IA
          </h3>
          <p className="text-indigo-800 leading-relaxed text-sm italic">"{analysis}"</p>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Fecha</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Propiedad</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Descripción</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600">Categoría</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 text-right">Monto</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.map(t => (
              <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm text-slate-600">{t.date}</td>
                <td className="px-6 py-4 text-sm font-medium text-slate-800">
                  {properties.find(p => p.id === t.propertyId)?.name || 'N/A'}
                </td>
                <td className="px-6 py-4 text-sm text-slate-600">{t.description}</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                    t.type === 'Ingreso' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'
                  }`}>
                    {t.category}
                  </span>
                </td>
                <td className={`px-6 py-4 text-sm font-bold text-right ${
                  t.type === 'Ingreso' ? 'text-emerald-600' : 'text-rose-600'
                }`}>
                  {t.type === 'Ingreso' ? '+' : '-'}${t.amount.toLocaleString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Accounting;

import React, { useState } from 'react';
import { MaintenanceTask, Property } from '../types';
import { getMaintenanceAdvice } from '../services/geminiService';

interface MaintenanceProps {
  tasks: MaintenanceTask[];
  setTasks: React.Dispatch<React.SetStateAction<MaintenanceTask[]>>;
  properties: Property[];
}

const Maintenance: React.FC<MaintenanceProps> = ({ tasks, setTasks, properties }) => {
  const [selectedTask, setSelectedTask] = useState<MaintenanceTask | null>(null);
  const [advice, setAdvice] = useState<string>('');
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);

  const fetchAdvice = async (task: MaintenanceTask) => {
    setSelectedTask(task);
    setIsLoadingAdvice(true);
    const result = await getMaintenanceAdvice(task.title, task.description);
    setAdvice(result || "No se pudo obtener consejo.");
    setIsLoadingAdvice(false);
  };

  const updateStatus = (taskId: string, newStatus: MaintenanceTask['status']) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Mantenimiento</h2>
          <p className="text-slate-500">Programa y supervisa las reparaciones de tus casas.</p>
        </div>
        <button className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-md hover:bg-indigo-700 transition-all">
