import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMaintenanceAdvice(taskTitle: string, description: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `As an expert property manager, provide quick advice (max 100 words) for this maintenance task: ${taskTitle}. Description: ${description}. Focus on cost efficiency and safety.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Could not retrieve automatic advice at this time.";
  }
}

export async function analyzeAccounting(data: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the following accounting data from a property management business and detect anomalies or suggest financial improvements. Data: ${data}. Respond concisely and professionally in English.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error analyzing accounting data.";
  }
}

