import React, { useState } from 'react';
import { MaintenanceTask, Property, MaintenanceStatus } from '../types';
import { getMaintenanceAdvice } from '../services/geminiService';

interface MaintenanceProps {
  tasks: MaintenanceTask[];
  setTasks: React.Dispatch<React.SetStateAction<MaintenanceTask[]>>;
  properties: Property[];
}

const STATUS_OPTIONS: MaintenanceStatus[] = [
  'Identified',
  'Assessing',
  'Quote',
  'Tech Review',
  'Approved by Tech',
  'Owner Review',
  'Approved by Owner',
  'Shop Materials',
  'Coordinate',
  'Scheduled',
  'Complete'
];

const getStatusColor = (status: MaintenanceStatus) => {
  switch (status) {
    case 'Identified': return 'bg-slate-100 text-slate-700';
    case 'Assessing': return 'bg-blue-100 text-blue-700';
    case 'Quote': return 'bg-amber-100 text-amber-700';
    case 'Tech Review': return 'bg-indigo-100 text-indigo-700';
    case 'Approved by Tech': return 'bg-indigo-200 text-indigo-800';
    case 'Owner Review': return 'bg-purple-100 text-purple-700';
    case 'Approved by Owner': return 'bg-purple-200 text-purple-800';
    case 'Shop Materials': return 'bg-cyan-100 text-cyan-700';
    case 'Coordinate': return 'bg-emerald-50 text-emerald-700';
    case 'Scheduled': return 'bg-emerald-100 text-emerald-700';
    case 'Complete': return 'bg-emerald-500 text-white';
    default: return 'bg-slate-100 text-slate-700';
  }
};

const Maintenance: React.FC<MaintenanceProps> = ({ tasks, setTasks, properties }) => {
  const [selectedTask, setSelectedTask] = useState<MaintenanceTask | null>(null);
  const [advice, setAdvice] = useState<string>('');
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);

  const fetchAdvice = async (task: MaintenanceTask) => {
    setSelectedTask(task);
    setIsLoadingAdvice(true);
    const result = await getMaintenanceAdvice(task.title, task.description);
    setAdvice(result || "Could not get advice.");
    setIsLoadingAdvice(false);
  };

  const updateStatus = (taskId: string, newStatus: MaintenanceStatus) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Maintenance Workflow</h2>
          <p className="text-slate-500">Track properties maintenance from identification to completion.</p>
        </div>
        <button className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-md hover:bg-indigo-700 transition-all">
          + New Maintenance Log
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Task List */}
        <div className="space-y-4 max-h-[700px] overflow-y-auto pr-2 custom-scrollbar">
          {tasks.map(task => (
            <div 
              key={task.id} 
              className={`bg-white p-5 rounded-2xl shadow-sm border-2 transition-all cursor-pointer ${
                selectedTask?.id === task.id ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:border-slate-200'
              }`}
              onClick={() => fetchAdvice(task)}
            >
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1">
                  <h3 className="font-bold text-slate-800 text-lg leading-tight">{task.title}</h3>
                  <p className="text-sm text-slate-500 mt-1">{properties.find(p => p.id === task.propertyId)?.name}</p>
                </div>
                <div className="flex flex-col items-end gap-2">
                  <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider shadow-sm ${
                    task.priority === 'High' ? 'bg-rose-500 text-white' : 
                    task.priority === 'Medium' ? 'bg-amber-400 text-white' : 'bg-slate-400 text-white'
                  }`}>
                    {task.priority}
                  </span>
                  <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${getStatusColor(task.status)}`}>
                    {task.status}
                  </span>
                </div>
              </div>

              <p className="text-sm text-slate-600 line-clamp-2 mb-4">{task.description}</p>

              <div className="flex justify-between items-center pt-4 border-t border-slate-50">
                <span className="text-xs text-slate-400 font-medium flex items-center gap-1">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                  Due: {task.dueDate}
                </span>

                <div className="flex items-center gap-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Stage:</label>
                  <select 
                    value={task.status}
                    onChange={(e) => updateStatus(task.id, e.target.value as MaintenanceStatus)}
                    onClick={(e) => e.stopPropagation()}
                    className="text-xs bg-slate-50 border border-slate-200 rounded-lg px-2 py-1 font-semibold text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none"
                  >
                    {STATUS_OPTIONS.map(opt => (
                      <option key={opt} value={opt}>{opt}</option>
                    ))}
                  </select>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Gemini Advice Panel */}
        <div className="bg-slate-900 text-white rounded-3xl p-8 flex flex-col h-full sticky top-4">
          {selectedTask ? (
            <>
              <h3 className="text-xl font-bold mb-2 flex items-center gap-2">
                <span className="p-2 bg-indigo-500 rounded-lg">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                  </svg>
                </span>
                Smart Dispatch Assistant
