  'Tech Review',
  'Approved by Tech',
  'Owner Review',
  'Approved by Owner',
  'Shop Materials',
  'Coordinate',
  'Scheduled',
  'Complete'
];

const getStatusColor = (status: MaintenanceStatus) => {
  switch (status) {
    case 'Identified': return 'bg-slate-100 text-slate-700';
    case 'Assessing': return 'bg-blue-100 text-blue-700';
    case 'Quote': return 'bg-amber-100 text-amber-700';
    case 'Tech Review': return 'bg-indigo-100 text-indigo-700';
    case 'Approved by Tech': return 'bg-indigo-200 text-indigo-800';
    case 'Owner Review': return 'bg-purple-100 text-purple-700';
    case 'Approved by Owner': return 'bg-purple-200 text-purple-800';
    case 'Shop Materials': return 'bg-cyan-100 text-cyan-700';
    case 'Coordinate': return 'bg-emerald-50 text-emerald-700';
    case 'Scheduled': return 'bg-emerald-100 text-emerald-700';
    case 'Complete': return 'bg-emerald-500 text-white';
    default: return 'bg-slate-100 text-slate-700';
  }
};

const Maintenance: React.FC<MaintenanceProps> = ({ tasks, setTasks, properties }) => {
  const [selectedTask, setSelectedTask] = useState<MaintenanceTask | null>(null);
  const [advice, setAdvice] = useState<string>('');
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);
  const [filterStatus, setFilterStatus] = useState<MaintenanceStatus | 'All'>('All');

  const counts = useMemo(() => {
    const acc: Record<string, number> = { All: tasks.length };
    tasks.forEach(task => {
      acc[task.status] = (acc[task.status] || 0) + 1;
    });
    return acc;
  }, [tasks]);

  const filteredTasks = useMemo(() => {
    if (filterStatus === 'All') return tasks;
    return tasks.filter(t => t.status === filterStatus);
  }, [tasks, filterStatus]);

  const fetchAdvice = async (task: MaintenanceTask) => {
    setSelectedTask(task);
    setIsLoadingAdvice(true);
    const result = await getMaintenanceAdvice(task.title, task.description);
    setAdvice(result || "Could not get advice.");
    setIsLoadingAdvice(false);
  };

  const updateStatus = (taskId: string, newStatus: MaintenanceStatus) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
    if (selectedTask?.id === taskId) {
      setSelectedTask(prev => prev ? { ...prev, status: newStatus } : null);
    }
  };

  const updateDateField = (taskId: string, field: 'assessmentDate' | 'scheduledDate', value: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, [field]: value } : t));
    if (selectedTask?.id === taskId) {
      setSelectedTask(prev => prev ? { ...prev, [field]: value } : null);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Maintenance Workflow</h2>
          <p className="text-slate-500">Track properties maintenance from identification to completion.</p>
        </div>
        <button className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-md hover:bg-indigo-700 transition-all flex-shrink-0">
          + New Maintenance Log
        </button>
      </div>

      {/* Filter Bar */}
      <div className="flex overflow-x-auto pb-4 gap-2 no-scrollbar scroll-smooth">
        {STATUS_OPTIONS.map((opt) => (
          <button
            key={opt}
            onClick={() => setFilterStatus(opt)}
            className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border-2 flex items-center gap-2 ${
              filterStatus === opt 
                ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                : 'bg-white border-slate-100 text-slate-500 hover:border-indigo-200'
            }`}
          >
            {opt}
            <span className={`px-1.5 py-0.5 rounded-full text-[10px] ${
              filterStatus === opt ? 'bg-indigo-500 text-white' : 'bg-slate-100 text-slate-400'
            }`}>
              {counts[opt] || 0}
            </span>
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Task List */}
        <div className="space-y-4 max-h-[700px] overflow-y-auto pr-2 custom-scrollbar">
          {filteredTasks.length > 0 ? (
            filteredTasks.map(task => (
              <div 
                key={task.id} 
                className={`bg-white p-5 rounded-2xl shadow-sm border-2 transition-all cursor-pointer ${
                  selectedTask?.id === task.id ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:border-slate-200'
                }`}
                onClick={() => fetchAdvice(task)}
              >
                <div className="flex justify-between items-start mb-3">
                  <div className="flex-1">
                    <h3 className="font-bold text-slate-800 text-lg leading-tight">{task.title}</h3>
                    <p className="text-sm text-slate-500 mt-1">{properties.find(p => p.id === task.propertyId)?.name}</p>
                  </div>
                  <div className="flex flex-col items-end gap-2">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider shadow-sm ${
                      task.priority === 'High' ? 'bg-rose-500 text-white' : 
                      task.priority === 'Medium' ? 'bg-amber-400 text-white' : 'bg-slate-400 text-white'
                    }`}>
                      {task.priority}
                    </span>
                    <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${getStatusColor(task.status)}`}>
                      {task.status}
                    </span>
                  </div>
                </div>

                <p className="text-sm text-slate-600 line-clamp-2 mb-4">{task.description}</p>

                {(task.status === 'Assessing' || task.status === 'Scheduled') && (
                  <div className="mb-4 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">
                      {task.status === 'Assessing' ? 'Assessment Time' : 'Execution Time'}
                    </p>
                    <p className="text-sm font-semibold text-indigo-600">
                      {task.status === 'Assessing' ? (task.assessmentDate || 'Not set') : (task.scheduledDate || 'Not set')}
                    </p>
                  </div>
                )}

                <div className="flex justify-between items-center pt-4 border-t border-slate-50">
                  <span className="text-xs text-slate-400 font-medium flex items-center gap-1">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    Due: {task.dueDate}
                  </span>

                  <div className="flex items-center gap-2">
                    <label className="text-[10px] font-bold text-slate-400 uppercase">Stage:</label>
                    <select 
                      value={task.status}
                      onChange={(e) => updateStatus(task.id, e.target.value as MaintenanceStatus)}
                      onClick={(e) => e.stopPropagation()}
                      className="text-xs bg-slate-50 border border-slate-200 rounded-lg px-2 py-1 font-semibold text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                      {STATUS_OPTIONS.filter(o => o !== 'All').map(opt => (
                        <option key={opt} value={opt}>{opt}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-white p-12 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-center">
              <div className="p-4 bg-slate-50 rounded-full mb-4">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <h4 className="text-lg font-bold text-slate-800 mb-1">No tasks found</h4>
              <p className="text-slate-400 text-sm">There are no maintenance tasks with status "{filterStatus}".</p>
              <button 
                onClick={() => setFilterStatus('All')}
                className="mt-4 text-indigo-600 font-bold text-sm hover:underline"
              >
                Clear filters
              </button>
            </div>
          )}
        </div>

        {/* Gemini Advice Panel */}
        <div className="bg-slate-900 text-white rounded-3xl p-8 flex flex-col h-full sticky top-4">
          {selectedTask ? (
            <>
              <h3 className="text-xl font-bold mb-2 flex items-center gap-2">
                <span className="p-2 bg-indigo-500 rounded-lg">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                  </svg>
                </span>
                Smart Dispatch Assistant
              </h3>
              <p className="text-slate-400 text-sm mb-6">Current Phase: <span className="text-indigo-400 font-bold uppercase">{selectedTask.status}</span></p>

              <div className="flex-1 overflow-y-auto">
                {isLoadingAdvice ? (
                  <div className="flex flex-col items-center justify-center h-full gap-4">
                    <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-indigo-400"></div>
                    <p className="text-indigo-300 text-sm animate-pulse">Consulting expert protocols...</p>
                  </div>
                ) : (
                  <div className="space-y-4 animate-fadeIn">
                    {/* Status Specific Date Input */}
                    {(selectedTask.status === 'Assessing' || selectedTask.status === 'Scheduled') && (
                      <div className="bg-slate-800 p-5 rounded-2xl border border-indigo-500/30">
                        <h4 className="text-xs font-bold text-indigo-300 uppercase mb-3 tracking-widest">
                          Set {selectedTask.status === 'Assessing' ? 'Assessment' : 'Schedule'} Time
                        </h4>
                        <input 
                          type="datetime-local" 
                          className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                          value={selectedTask.status === 'Assessing' ? (selectedTask.assessmentDate || '') : (selectedTask.scheduledDate || '')}
                          onChange={(e) => updateDateField(selectedTask.id, selectedTask.status === 'Assessing' ? 'assessmentDate' : 'scheduledDate', e.target.value)}
                        />
                      </div>
                    )}

                    <div className="bg-slate-800 p-5 rounded-2xl border border-slate-700 shadow-inner">
                      <h4 className="text-xs font-bold text-indigo-300 uppercase mb-3 tracking-widest">Procedural Advice</h4>
                      <p className="text-slate-200 text-sm leading-relaxed italic">
                        {advice}
                      </p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                        <p className="text-[10px] text-indigo-400 uppercase font-bold mb-1 tracking-wider">Financial Impact</p>
                        <p className="text-lg font-bold text-white">Market Rate Est.</p>
                        <p className="text-xs text-slate-400 mt-1">Check current quote</p>
                      </div>
                      <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                        <p className="text-[10px] text-emerald-400 uppercase font-bold mb-1 tracking-wider">Target Date</p>
                        <p className="text-lg font-bold text-white">{selectedTask.dueDate}</p>
                        <p className="text-xs text-slate-400 mt-1">Review availability</p>
                      </div>
                    </div>
                  </div>
                )}
              </div>
              <button className="mt-6 w-full py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95">
                Advance to Next Phase
              </button>
            </>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-6">
              <div className="p-6 bg-slate-800 rounded-full border border-slate-700">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 11c0 3.517-1.009 6.799-2.753 9.571m-3.44-2.04l.054-.09A10.003 10.003 0 0012 3m0 18a10.003 10.003 0 01-1.212-4.346m0 0L12 11m0 0l3.44 2.04m-3.44-2.04v10m6.88-9.571A10.003 10.003 0 0012 3m0 0V3m0 0l3.44 2.04" />
                </svg>
              </div>
              <div>
                <h4 className="text-lg font-bold text-white mb-2">Workflow Hub</h4>
                <p className="text-slate-400 max-w-xs mx-auto text-sm leading-relaxed">Select a maintenance record to see intelligent step-by-step guidance for the current project stage.</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Maintenance;

export interface Property {
  id: string;
  name: string;
  address: string;
  type: 'House' | 'Apartment' | 'Commercial';
  status: 'Occupied' | 'Available' | 'Maintenance';
}

export interface Transaction {
  id: string;
  date: string;
  propertyId: string;
  description: string;
  amount: number;
  category: 'Rent' | 'Maintenance' | 'Utilities' | 'Taxes' | 'Other';
  type: 'Income' | 'Expense';
}

export type MaintenanceStatus = 
  | 'Identified' 
  | 'Assessing' 
  | 'Quote' 
  | 'Tech Review' 
  | 'Approved by Tech' 
  | 'Owner Review' 
  | 'Approved by Owner' 
  | 'Shop Materials' 
  | 'Coordinate' 
  | 'Scheduled' 
  | 'Complete';

export interface MaintenanceTask {
  id: string;
  propertyId: string;
  title: string;
  description: string;
  priority: 'Low' | 'Medium' | 'High';
  status: MaintenanceStatus;
  dueDate: string;
  assessmentDate?: string;
  scheduledDate?: string;
}

export interface InvoiceItem {
  description: string;
  price: number;
}

export interface Invoice {
  id: string;
  propertyId: string;
  tenantName: string;
  date: string;
  amount: number;
  status: 'Paid' | 'Pending' | 'Overdue';
  items: InvoiceItem[];
}

export interface Quote {
  id: string;
  propertyId: string;
  clientName: string;
  date: string;
  expiryDate: string;
  amount: number;
  status: 'Draft' | 'Sent' | 'Accepted' | 'Declined';
  items: InvoiceItem[];
}

export interface RecurringInvoice {
  id: string;
  propertyId: string;
  tenantName: string;
  amount: number;
  frequency: 'Monthly' | 'Quarterly' | 'Yearly';
  nextDate: string;
  status: 'Active' | 'Paused';
}

export interface Payment {
  id: string;
  invoiceId?: string;
  propertyId: string;
  amount: number;
  date: string;
  method: 'Transfer' | 'Cash' | 'Card' | 'Check';
  reference: string;
}

export enum View {
  Dashboard = 'dashboard',
  Accounting = 'accounting',
  Maintenance = 'maintenance',
  Billing = 'billing',
  Properties = 'properties'
}

