  invoices: Invoice[];
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
  quotes: Quote[];
  recurringInvoices: RecurringInvoice[];
  payments: Payment[];
  properties: Property[];
}

type BillingSubView = 'quotes' | 'retainers' | 'invoices' | 'recurring' | 'payments';

const Billing: React.FC<BillingProps> = ({ 
  invoices, 
  setInvoices, 
  quotes, 
  recurringInvoices, 
  payments, 
  properties 
