    { id: 'retainers', label: 'Retainer Invoices' },
    { id: 'invoices', label: 'Invoices' },
    { id: 'recurring', label: 'Recurring' },
    { id: 'payments', label: 'Payments' },
  ];

  const renderActiveContent = () => {
    switch (activeTab) {
      case 'quotes':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fadeIn">
            {quotes.map(quote => (
              <div key={quote.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                <div className="flex justify-between items-start mb-4">
                  <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                    quote.status === 'Accepted' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
                  }`}>
                    {quote.status}
                  </span>
                  <p className="text-xs text-slate-400 font-medium">Expires: {quote.expiryDate}</p>
                </div>
                <h3 className="font-bold text-slate-800 text-lg mb-1">{quote.clientName}</h3>
                <p className="text-sm text-slate-500 mb-4">{properties.find(p => p.id === quote.propertyId)?.name}</p>
                <div className="pt-4 border-t border-slate-50 flex justify-between items-center">
                  <span className="text-sm font-bold text-slate-800">Total Est.</span>
                  <span className="text-lg font-black text-indigo-600">${quote.amount.toLocaleString()}</span>
                </div>
              </div>
            ))}
          </div>
        );

      case 'retainers':
        return (
          <div className="bg-white rounded-2xl p-12 border-2 border-dashed border-slate-100 text-center animate-fadeIn">
            <p className="text-slate-400 italic">No retainer invoices found. Create a retainer to secure funds for large projects.</p>
            <button className="mt-4 text-indigo-600 font-bold">+ New Retainer</button>
          </div>
        );

      case 'invoices':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fadeIn">
            {invoices.map(invoice => (
              <div key={invoice.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden group">
                <div className="p-6">
                  <div className="flex justify-between items-start mb-4">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                      invoice.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                    }`}>
                      {invoice.status}
                    </span>
                    <p className="text-xs text-slate-400 font-medium">{invoice.date}</p>
                  </div>
                  <h3 className="font-bold text-slate-800 text-lg mb-1">{invoice.tenantName}</h3>
                  <p className="text-sm text-slate-500 mb-4">{properties.find(p => p.id === invoice.propertyId)?.name}</p>
                  <div className="space-y-2 mb-6">
                    {invoice.items.map((item, idx) => (
                      <div key={idx} className="flex justify-between text-sm">
                        <span className="text-slate-500">{item.description}</span>
                        <span className="font-semibold text-slate-700">${item.price.toLocaleString()}</span>
                      </div>
                    ))}
                    <div className="pt-2 border-t border-slate-50 flex justify-between items-center">
                      <span className="text-sm font-bold text-slate-800">Total</span>
                      <span className="text-lg font-black text-indigo-600">${invoice.amount.toLocaleString()}</span>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button className="flex-1 py-2 bg-slate-100 text-slate-700 rounded-lg text-sm font-semibold hover:bg-slate-200 transition-colors">Download</button>
                    <button className="flex-1 py-2 bg-indigo-600 text-white rounded-lg text-sm font-semibold hover:bg-indigo-700 transition-colors">Send</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        );

      case 'recurring':
        return (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden animate-fadeIn">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tenant</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Frequency</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Next Date</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Amount</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {recurringInvoices.map(rec => (
                  <tr key={rec.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 text-sm font-bold text-slate-800">{rec.tenantName}</td>
                    <td className="px-6 py-4 text-sm text-slate-500">{rec.frequency}</td>
                    <td className="px-6 py-4 text-sm text-slate-500">{rec.nextDate}</td>
                    <td className="px-6 py-4 text-sm font-bold text-indigo-600">${rec.amount.toLocaleString()}</td>
                    <td className="px-6 py-4">
                      <span className="px-2 py-1 bg-emerald-50 text-emerald-600 text-[10px] font-black uppercase rounded-full">
                        {rec.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );

      case 'payments':
        return (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden animate-fadeIn">
             <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Date</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Method</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Reference</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Amount</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {payments.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 text-sm text-slate-600">{p.date}</td>
                    <td className="px-6 py-4 text-sm text-slate-500">{p.method}</td>
                    <td className="px-6 py-4 text-sm font-mono text-slate-400">{p.reference}</td>
                    <td className="px-6 py-4 text-sm font-bold text-right text-emerald-600">${p.amount.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Billing Center</h2>
          <p className="text-slate-500">Comprehensive financial tools for property revenue.</p>
        </div>
        <div className="flex gap-2">
          <button className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-md hover:bg-indigo-700 transition-all">
            + Action
          </button>
        </div>
      </div>

      {/* Secondary Sub-Navigation */}
      <div className="flex border-b border-slate-200">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-6 py-3 text-sm font-bold transition-all relative ${
              activeTab === tab.id 
                ? 'text-indigo-600' 
                : 'text-slate-400 hover:text-slate-600'
            }`}
          >
            {tab.label}
            {activeTab === tab.id && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-600 rounded-full" />
            )}
          </button>
        ))}
      </div>

      <div className="mt-6">
        {renderActiveContent()}
      </div>
    </div>
  );
};

export default Billing;

export interface Property {
  id: string;
  name: string;
  address: string;
  type: 'House' | 'Apartment' | 'Commercial';
  status: 'Occupied' | 'Available' | 'Maintenance';
}

export interface Transaction {
  id: string;
  date: string;
  propertyId: string;
  description: string;
  amount: number;
  category: 'Rent' | 'Maintenance' | 'Utilities' | 'Taxes' | 'Other';
  type: 'Income' | 'Expense';
}

export type MaintenanceStatus = 
  | 'Identified' 
  | 'Assessing' 
  | 'Quote' 
  | 'Tech Review' 
  | 'Approved by Tech' 
  | 'Owner Review' 
  | 'Approved by Owner' 
  | 'Shop Materials' 
  | 'Coordinate' 
  | 'Scheduled' 
  | 'Complete';

export interface MaintenanceTask {
  id: string;
  propertyId: string;
  title: string;
  description: string;
  priority: 'Low' | 'Medium' | 'High';
  status: MaintenanceStatus;
  dueDate: string;
  assessmentDate?: string;
  scheduledDate?: string;
}

export interface InvoiceItem {
  description: string;
  price: number;
}

export interface Invoice {
  id: string;
  propertyId: string;
  tenantName: string;
  date: string;
  amount: number;
  status: 'Paid' | 'Pending' | 'Overdue';
  items: InvoiceItem[];
}

export interface Quote {
  id: string;
  propertyId: string;
  clientName: string;
  date: string;
  expiryDate: string;
  amount: number;
  status: 'Draft' | 'Sent' | 'Accepted' | 'Declined';
  items: InvoiceItem[];
}

export interface RecurringInvoice {
  id: string;
  propertyId: string;
  tenantName: string;
  amount: number;
  frequency: 'Monthly' | 'Quarterly' | 'Yearly';
  nextDate: string;
  status: 'Active' | 'Paused';
}

export interface Payment {
  id: string;
  invoiceId?: string;
  propertyId: string;
  amount: number;
  date: string;
  method: 'Transfer' | 'Cash' | 'Card' | 'Check';
  reference: string;
}

export interface Lease {
  id: string;
  propertyId: string;
  tenantName: string;
  startDate: string;
  endDate: string;
  monthlyRent: number;
  securityDeposit: number;
  status: 'Active' | 'Expiring' | 'Terminated' | 'Pending';
}

