import React, { useState, useMemo } from 'react';
import { Lease, Property } from '../types';

interface LeasesProps {
  leases: Lease[];
  setLeases: React.Dispatch<React.SetStateAction<Lease[]>>;
  properties: Property[];
}

const Leases: React.FC<LeasesProps> = ({ leases, setLeases, properties }) => {
  const [filterStatus, setFilterStatus] = useState<Lease['status'] | 'All'>('All');

  const filteredLeases = useMemo(() => {
    if (filterStatus === 'All') return leases;
    return leases.filter(l => l.status === filterStatus);
  }, [leases, filterStatus]);

  const getStatusStyle = (status: Lease['status']) => {
    switch (status) {
      case 'Active': return 'bg-emerald-100 text-emerald-700';
      case 'Expiring': return 'bg-amber-100 text-amber-700';
      case 'Terminated': return 'bg-rose-100 text-rose-700';
      case 'Pending': return 'bg-slate-100 text-slate-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Leases & Agreements</h2>
          <p className="text-slate-500">Manage tenant contracts and occupancy periods.</p>
        </div>
        <button className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold shadow-md hover:bg-indigo-700 transition-all">
          + New Lease
        </button>
      </div>

      <div className="flex gap-2 border-b border-slate-200 pb-2 overflow-x-auto no-scrollbar">
        {['All', 'Active', 'Pending', 'Expiring', 'Terminated'].map((status) => (
          <button
            key={status}
            onClick={() => setFilterStatus(status as any)}
            className={`px-4 py-2 text-sm font-bold transition-all rounded-lg whitespace-nowrap ${
              filterStatus === status 
                ? 'bg-indigo-50 text-indigo-700' 
                : 'text-slate-400 hover:text-slate-600'
            }`}
          >
            {status}
          </button>
        ))}
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tenant</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Property</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Term</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Monthly Rent</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredLeases.map(lease => (
                <tr key={lease.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800">{lease.tenantName}</div>
                    <div className="text-xs text-slate-400">ID: {lease.id}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm font-medium text-slate-700">
                      {properties.find(p => p.id === lease.propertyId)?.name || 'Unknown'}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm text-slate-600">{lease.startDate} — {lease.endDate}</div>
                  </td>
                  <td className="px-6 py-4 font-bold text-indigo-600">
                    ${lease.monthlyRent.toLocaleString()}/mo
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${getStatusStyle(lease.status)}`}>
                      {lease.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="text-slate-400 hover:text-indigo-600 font-bold text-sm">Manage</button>
                  </td>
                </tr>
              ))}
              {filteredLeases.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-400 italic">
                    No leases found matching the selected status.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

